// src/components/Footer/index.jsx

import React from 'react';
import { Link } from 'react-router-dom';
import s from './Footer.module.css';

// Импорт иконок соцсетей (требует установки 'react-icons')
import { FaInstagram, FaWhatsapp } from 'react-icons/fa';

const Footer = () => {
  return (
    <footer className={s.footer}>
      <div className={s.container}>

        {/* 1. Блок Контактов */}
        <div className={s.contactBlock}>
          <h3>Контакты</h3>
          <p>Email: info@gardenstore.com</p>
          <p>Телефон: +49 123 456 7890</p>
          <p>Адрес: 123 Garden St, Berlin, Germany</p>
        </div>

        {/* 2. Блок Навигации */}
        <div className={s.navBlock}>
          <h3>Навигация</h3>
          <Link to="/categories" className={s.link}>Каталог</Link>
          <Link to="/products" className={s.link}>Все товары</Link>
          <Link to="/cart" className={s.link}>Корзина</Link>
          <Link to="/coupon" className={s.link}>Скидки</Link>
        </div>

        {/* 3. Блок Соцсетей */}
        <div className={s.socialBlock}>
          <h3>Следите за нами</h3>
          <div className={s.socialIcons}>
            <a href="https://instagram.com" target="_blank" rel="noopener noreferrer">
              <FaInstagram className={s.socialIcon} />
            </a>
            <a href="https://wa.me/491234567890" target="_blank" rel="noopener noreferrer">
              <FaWhatsapp className={s.socialIcon} />
            </a>
            {/* ... другие иконки ... */}
          </div>
        </div>
      </div>

      {/* Копирайт */}
      <div className={s.copyright}>
        <p>© {new Date().getFullYear()} Garden Store. Все права защищены.</p>
      </div>
    </footer>
  );
};

export default Footer;
